'use strict';

const express = require('express');
const { expressMiddleware, router } = require('fortress');

const app = express();

// Apply Fortress express middleware
app.use(expressMiddleware());

// Mount Fortress router for /status/fo
app.use('/status/fo', router);

module.exports = app;
